20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PRICE = 60;
22	
23	interface Item {
24	  type: string;
25	  enchantment?: number;
26	  cursed?: boolean;
27	}
28	
29	const CURSED_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	const FIRST_INSURANCE_RATE = 0.1;
33	
34	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
35	
36	const itemSurcharge = (item: Item): number => {
37	  const base = basePremiumFor(item.type);
38	  let surcharge = 0;
39	  if (item.cursed) {
40	    surcharge += base * CURSED_SURCHARGE_RATE;
41	  }
42	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
43	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
44	  }
45	  return surcharge;
46	};
47	
48	const quotePremium = (items: Array<Item>): number => {
49	  const typeCounts: Record<string, number> = {};
50	  for (const item of items) {
51	    typeCounts[item.type] = (typeCounts[item.type] ?? 0) + 1;
52	  }
53	  let policyBasePremium = 0;
54	  for (const [type, count] of Object.entries(typeCounts)) {
55	    if (count === COMPONENT_BLOCK_SIZE) {
56	      policyBasePremium += COMPONENT_BLOCK_PRICE;
57	    } else {
58	      policyBasePremium += count * basePremiumFor(type);
59	    }
60	  }
61	  let totalSurcharges = 0;
62	  for (const item of items) {
63	    totalSurcharges += itemSurcharge(item);
64	  }
65	  const firstInsurance = policyBasePremium * FIRST_INSURANCE_RATE;
66	  return policyBasePremium + totalSurcharges + firstInsurance + PROCESSING_FEE;
67	};
